// @ts-nocheck
import { useState, useEffect } from "react";

const SUPABASE_URL = "https://vuzyvdfftdjrgbchpebk.supabase.co";
const SUPABASE_KEY = "eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6InZ1enl2ZGZmdGRqcmdiY2hwZWJrIiwicm9sZSI6ImFub24iLCJpYXQiOjE3NzgxNzg2NjYsImV4cCI6MjA5Mzc1NDY2Nn0.G0__BqrBq_Tsg2raq3rbyxzPeCgzxGE4kTCm9uZGSl0";
const LOGO_B64 = "data:image/png;base64,";

const USUARIOS = { cristian: "cristian1492", valentina: "valentina1492", daniel: "daniel1492" };
const PUESTOS = ["Bacha 1","Bacha 2","Cafetería","Caja","Recepcionista","Encargado Salón","Cocina 1","Cocina 2","Cocina 3","Cocina 4","Cocina 5","Cocina 6","Cocina 7","Cocina 8"];
const PAGADORES = ["Cristian","Valentina","Daniel"];
const TURNOS = ["Mañana","Noche","Evento"];
const VERSION = "v2.2";
const YEAR = "2026";

const BG="#f6f7fb",CARD="#ffffff",CARD2="#f3f4f6",BORDER="#d6d9e0",TEXT="#101218";
const BRIGHT="#111111",MUTED="#555b66",ACCENT="#2a2f3a",GREEN="#22c55e",GDIM="#22c55e1f";
const RED="#dc2626",RDIM="#dc262615";
const FONT="'Atkinson Hyperlegible', 'Segoe UI', Tahoma, sans-serif";

const todayStr=()=>new Date().toISOString().split("T")[0];
const uid=()=>Math.random().toString(36).slice(2,9);
const mkDistrib=()=>PUESTOS.map(p=>({puesto:p,empId:"",horas:0}));
const fmtN=(n)=>Number(n)>0?`$${Number(n).toFixed(2)}`:"—";
const fmtDate=(d)=>{if(!d)return"—";const[y,m,day]=d.split("-");return`${day}/${m}/${y}`;};
const toStamp=(d)=>new Date(`${d}T00:00:00`).getTime();
const sortByFechaDesc=(arr)=>[...arr].sort((a,b)=>toStamp(b.fechaPropina)-toStamp(a.fechaPropina));
const sortByFechaAsc=(arr)=>[...arr].sort((a,b)=>toStamp(a.fechaPropina)-toStamp(b.fechaPropina));

const sb=async(path,options={})=>{
  const res=await fetch(`${SUPABASE_URL}/rest/v1${path}`,{...options,headers:{"apikey":SUPABASE_KEY,"Authorization":`Bearer ${SUPABASE_KEY}`,"Content-Type":"application/json","Prefer":"return=representation",...(options.headers||{})}});
  const text=await res.text();if(!res.ok)throw new Error(text);return text?JSON.parse(text):[];
};

const getPersonal=()=>sb("/propinas_personal?order=nombre.asc");
const getHistorial=()=>sb("/propinas_historial?order=created_at.desc");
const getBorradores=()=>sb("/propinas_borradores?order=created_at.desc");
const addEmp=(nombre)=>sb("/propinas_personal",{method:"POST",body:JSON.stringify({nombre})});
const delEmp=(id)=>sb(`/propinas_personal?id=eq.${id}`,{method:"DELETE",headers:{"Prefer":""}});
const addReg=(r)=>sb("/propinas_historial",{method:"POST",body:JSON.stringify({id:r.id,fecha_pago:r.fechaPago,fecha_propina:r.fechaPropina,turno:r.turno,pagado_por:r.pagadoPor,monto:r.monto,total_hs:r.totalHs,rate_ph:r.ratePH,detalles:r.detalles,created_by:r.createdBy})});
const addBorrador=(b)=>sb("/propinas_borradores",{method:"POST",body:JSON.stringify({id:b.id,fecha_pago:b.fechaPago,fecha_propina:b.fechaPropina,turno:b.turno,pagado_por:b.pagadoPor,distribucion:b.distribucion,created_by:b.createdBy})});
const delBorrador=(id)=>sb(`/propinas_borradores?id=eq.${id}`,{method:"DELETE",headers:{"Prefer":""}});
const patchReg=(id,dt)=>sb(`/propinas_historial?id=eq.${id}`,{method:"PATCH",body:JSON.stringify({detalles:dt})});
const deleteReg=(id)=>sb(`/propinas_historial?id=eq.${id}`,{method:"DELETE",headers:{"Prefer":""}});

const INPUT={background:CARD2,border:`1px solid ${BORDER}`,borderRadius:10,color:TEXT,fontFamily:FONT,fontSize:16,padding:"13px 14px",outline:"none",boxSizing:"border-box",WebkitAppearance:"none",width:"100%"};
const CARD_S={background:CARD,border:`1px solid ${BORDER}`,borderRadius:14,padding:"16px",marginBottom:12};
const pill=(a)=>({flex:1,padding:"10px 4px",borderRadius:10,border:`1px solid ${a?ACCENT:BORDER}`,background:a?"#eef1f6":"transparent",color:a?BRIGHT:MUTED,fontFamily:FONT,fontSize:14,fontWeight:a?600:500,cursor:"pointer"});
const LABEL={fontSize:13,color:MUTED,display:"block",marginBottom:6};
const SECTIT={fontSize:11,color:MUTED,letterSpacing:2.5,textTransform:"uppercase",fontWeight:700,marginBottom:12};

function FooterBar({ fixed = false }){
  return (
    <div style={{position:fixed?"fixed":"static",bottom:fixed?58:"auto",left:fixed?"50%":"auto",transform:fixed?"translateX(-50%)":"none",width:"100%",maxWidth:500,padding:"8px 12px",textAlign:"center",color:MUTED,fontSize:12,background:fixed?BG:"transparent",zIndex:15}}>
      FAROGESTION - PROPINERO - Desarrollo Daniel Santini · {VERSION}
    </div>
  );
}

export default function App(){
  const[usuario,setUsuario]=useState(localStorage.getItem("fg_usuario")||"");
  const[usuarioSel,setUsuarioSel]=useState("");
  const[pass,setPass]=useState("");
  const[loginError,setLoginError]=useState("");
  const[tab,setTab]=useState("registrar");
  const[personal,setPersonal]=useState([]);
  const[historial,setHistorial]=useState([]);
  const[borradores,setBorradores]=useState([]);
  const[ready,setReady]=useState(false);
  const[error,setError]=useState("");
  const[fechaPago,setFechaPago]=useState(todayStr());
  const[fechaPropina,setFechaPropina]=useState(todayStr());
  const[turno,setTurno]=useState("");
  const[pagadoPor,setPagadoPor]=useState("");
  const[monto,setMonto]=useState("");
  const[distrib,setDistrib]=useState(mkDistrib());
  const[flash,setFlash]=useState(false);
  const[nuevoNombre,setNuevoNombre]=useState("");
  const[expandedId,setExpandedId]=useState(null);
  const[selectedEmp,setSelectedEmp]=useState(null);
  const[convertMode,setConvertMode]=useState(null);

  useEffect(()=>{const l=document.createElement("link");l.href="https://fonts.googleapis.com/css2?family=Atkinson+Hyperlegible:wght@400;700&display=swap";l.rel="stylesheet";document.head.appendChild(l);},[]);

  const login=(u,p)=>{
    if(USUARIOS[u]&&USUARIOS[u]===p){
      localStorage.setItem("fg_usuario",u);
      setUsuario(u);
      setUsuarioSel("");
      setPass("");
      setLoginError("");
      cargarDatos();
    }else{
      setLoginError("Usuario o contraseña incorrectos");
    }
  };

  const logout=()=>{
    localStorage.removeItem("fg_usuario");
    setUsuario("");
    setUsuarioSel("");
    setPass("");
  };

  const cargarDatos=async()=>{
    try{
      const[p,h,b]=await Promise.all([getPersonal(),getHistorial(),getBorradores()]);
      setPersonal(Array.isArray(p)?p:[]);
      const historialMapped=Array.isArray(h)?h.map(r=>({id:r.id,fechaPago:r.fecha_pago,fechaPropina:r.fecha_propina,turno:r.turno,pagadoPor:r.pagado_por,monto:r.monto,totalHs:r.total_hs,ratePH:r.rate_ph,detalles:r.detalles||[],createdBy:r.created_by})):[];
      const borradoresMapped=Array.isArray(b)?b.map(br=>({id:br.id,fechaPago:br.fecha_pago,fechaPropina:br.fecha_propina,turno:br.turno,pagadoPor:br.pagado_por,distribucion:br.distribucion||[],createdBy:br.created_by})):[];
      setHistorial(sortByFechaDesc(historialMapped));
      setBorradores(sortByFechaDesc(borradoresMapped));
    }catch(e){setError("Error al cargar datos.");}
    setReady(true);
  };

  useEffect(()=>{if(usuario)cargarDatos();},[usuario]);

  const montoNum=parseFloat(monto)||0;
  const totalHs=distrib.reduce((s,r)=>s+(r.empId&&r.horas>0?r.horas:0),0);
  const ratePH=totalHs>0&&montoNum>0?montoNum/totalHs:0;
  const cobroRow=(r)=>r.empId&&r.horas>0?ratePH*r.horas:0;
  const updDistrib=(i,key,val)=>setDistrib(d=>d.map((r,idx)=>{if(idx!==i)return r;const u={...r,[key]:val};if(key==="empId"&&!val)u.horas=0;return u;}));
  const togglePill=(val,current,setter)=>setter(current===val?"":val);

  const guardarBorrador=async()=>{
    if(!fechaPago||!fechaPropina||!turno||!pagadoPor){alert("Completá: fechas, turno y quién pagó.");return;}
    const borrador={id:uid(),fechaPago,fechaPropina,turno,pagadoPor,distribucion:distrib,createdBy:usuario};
    try{
      await addBorrador(borrador);
      setBorradores(sortByFechaDesc([borrador,...borradores]));
      setFechaPago(todayStr());setFechaPropina(todayStr());setTurno("");setPagadoPor("");setDistrib(mkDistrib());
      setFlash(true);setTimeout(()=>{setFlash(false);setTab("borradores");},1300);
    }catch{alert("Error al guardar borrador.");}
  };

  const convertirBorrador=async(borrador,montoTotal)=>{
    const montoNum=parseFloat(montoTotal)||0;
    if(!montoNum){alert("Ingresá el monto.");return;}
    const distribFull=borrador.distribucion.filter(r=>r.empId&&r.horas>0);
    if(!distribFull.length){alert("No hay empleados asignados en el borrador.");return;}
    const totalHsB=distribFull.reduce((s,r)=>s+r.horas,0);
    const ratePHB=montoNum/totalHsB;
    const detalles=distribFull.map(r=>({puesto:r.puesto,empId:r.empId,empNombre:personal.find(p=>p.id===r.empId)?.nombre||"?",horas:r.horas,cobro:ratePHB*r.horas,cobrado:false}));
    const reg={id:uid(),fechaPago:borrador.fechaPago,fechaPropina:borrador.fechaPropina,turno:borrador.turno,pagadoPor:borrador.pagadoPor,monto:montoNum,totalHs:totalHsB,ratePH:ratePHB,detalles,createdBy:usuario};
    try{
      await addReg(reg);
      await delBorrador(borrador.id);
      setHistorial(sortByFechaDesc([reg,...historial]));
      setBorradores(sortByFechaDesc(borradores.filter(b=>b.id!==borrador.id)));
      setConvertMode(null);
      setFlash(true);setTimeout(()=>{setFlash(false);setTab("historial");},1300);
    }catch(e){alert("Error al convertir borrador.");}
  };

  const guardarPropina=async()=>{
    if(!fechaPago||!fechaPropina||!turno||!pagadoPor||!montoNum){alert("Completá todos los campos.");return;}
    const detalles=distrib.filter(r=>r.empId&&r.horas>0).map(r=>({puesto:r.puesto,empId:r.empId,empNombre:personal.find(p=>p.id===r.empId)?.nombre||"?",horas:r.horas,cobro:ratePH*r.horas,cobrado:false}));
    const reg={id:uid(),fechaPago,fechaPropina,turno,pagadoPor,monto:montoNum,totalHs,ratePH,detalles,createdBy:usuario};
    try{
      await addReg(reg);
      setHistorial(sortByFechaDesc([reg,...historial]));
      setFechaPago(todayStr());setFechaPropina(todayStr());setTurno("");setPagadoPor("");setMonto("");setDistrib(mkDistrib());
      setFlash(true);setTimeout(()=>{setFlash(false);setTab("historial");},1300);
    }catch{alert("Error al guardar.");}
  };

  const toggleCobrado=async(regId,idx)=>{
    const updated=historial.map(h=>{if(h.id!==regId)return h;return{...h,detalles:h.detalles.map((d,i)=>i===idx?{...d,cobrado:!d.cobrado}:d)};});
    const reg=updated.find(h=>h.id===regId);
    try{await patchReg(regId,reg.detalles);setHistorial(sortByFechaDesc(updated));}catch{alert("Error al actualizar.");}
  };

  const eliminarReg=async(regId)=>{try{await deleteReg(regId);setHistorial(sortByFechaDesc(historial.filter(h=>h.id!==regId)));setExpandedId(null);}catch{alert("Error al eliminar.");}};

  const addPersonal=async()=>{
    const nombre=nuevoNombre.trim();if(!nombre)return;
    if(personal.some(p=>p.nombre.toLowerCase()===nombre.toLowerCase())){alert("Ya existe ese nombre.");return;}
    try{
      const res=await addEmp(nombre);
      const nuevo=res[0]||{id:uid(),nombre};
      setPersonal([...personal,nuevo].sort((a,b)=>a.nombre.localeCompare(b.nombre,"es")));
      setNuevoNombre("");
    }catch{alert("Error al agregar.");}
  };

  const delPersonal=async(id)=>{try{await delEmp(id);setPersonal(personal.filter(p=>p.id!==id));setSelectedEmp(null);}catch{alert("Error al eliminar.");}};

  if(!usuario){
    return(
      <div style={{minHeight:"100vh",background:BG,display:"flex",alignItems:"center",justifyContent:"center",padding:"20px"}}>
        <div style={{width:"100%",maxWidth:360}}>
          <div style={{textAlign:"center",marginBottom:32}}>
            <img src={LOGO_B64} alt="FaroGestion" style={{height:60,marginBottom:16}}/>
            <div style={{fontSize:24,fontWeight:700,color:BRIGHT}}>Propinero</div>
            <div style={{fontSize:13,color:MUTED,marginTop:4}}>{VERSION}</div>
          </div>
          <div style={CARD_S}>
            <div style={{fontSize:16,fontWeight:700,color:BRIGHT,marginBottom:16}}>Iniciar sesión</div>
            <div style={{marginBottom:12}}>
              <label style={LABEL}>Usuario</label>
              <select value={usuarioSel} onChange={e=>setUsuarioSel(e.target.value)} style={INPUT}>
                <option value="">Seleccionar...</option>
                <option value="cristian">Cristian</option>
                <option value="valentina">Valentina</option>
                <option value="daniel">Daniel</option>
              </select>
            </div>
            <div style={{marginBottom:16}}>
              <label style={LABEL}>Contraseña</label>
              <input type="password" value={pass} onChange={e=>setPass(e.target.value)} onKeyDown={e=>e.key==="Enter"&&login(usuarioSel,pass)} style={INPUT}/>
            </div>
            {loginError&&<div style={{fontSize:13,color:RED,marginBottom:12,padding:"8px",background:RDIM,borderRadius:8}}>{loginError}</div>}
            <button onClick={()=>login(usuarioSel,pass)} style={{width:"100%",padding:"13px",background:BRIGHT,border:"none",borderRadius:10,color:"#fff",fontFamily:FONT,fontSize:16,fontWeight:700,cursor:"pointer"}}>
              Entrar
            </button>
          </div>
          <FooterBar />
        </div>
      </div>
    );
  }

  if(!ready)return(
    <div style={{minHeight:"100vh",background:BG,display:"flex",alignItems:"center",justifyContent:"center",flexDirection:"column",gap:20}}>
      <img src={LOGO_B64} alt="FaroGestion" style={{width:200,opacity:0.8}}/>
      <div style={{width:32,height:32,border:`2px solid ${BORDER}`,borderTopColor:ACCENT,borderRadius:"50%",animation:"spin 0.8s linear infinite"}}/>
      <FooterBar />
      <style>{`@keyframes spin{to{transform:rotate(360deg)}}`}</style>
    </div>
  );

  const TABS=[
    {id:"registrar",icon:"✏️",label:"Registrar"},
    {id:"borradores",icon:"📝",label:"Borradores"},
    {id:"historial",icon:"📋",label:"Historial"},
    {id:"registros",icon:"👤",label:"Registros"},
    {id:"personal",icon:"👥",label:"Personal"},
  ];

  return(
    <div style={{minHeight:"100vh",background:BG,color:TEXT,fontFamily:FONT,paddingBottom:122,maxWidth:500,margin:"0 auto"}}>
      <div style={{background:CARD,borderBottom:`1px solid ${BORDER}`,padding:"10px 16px",position:"sticky",top:0,zIndex:10}}>
        <div style={{display:"flex",justifyContent:"space-between",alignItems:"center"}}>
          <img src={LOGO_B64} alt="FaroGestion" style={{height:36}}/>
          <div style={{textAlign:"right"}}>
            <div style={{fontSize:17,fontWeight:700,color:BRIGHT}}>Propinero</div>
            <div style={{fontSize:11,color:MUTED}}>🔑 {usuario.charAt(0).toUpperCase()+usuario.slice(1)}</div>
          </div>
          <button onClick={logout} style={{background:"none",border:`1px solid ${BORDER}`,borderRadius:8,color:RED,padding:"6px 12px",fontFamily:FONT,fontSize:13,cursor:"pointer"}}>Salir</button>
        </div>
      </div>

      <div style={{padding:"14px 14px 0"}}>
        {tab==="registrar"&&<RegistrarTab personal={personal} distrib={distrib} updDistrib={updDistrib} fechaPago={fechaPago} setFechaPago={setFechaPago} fechaPropina={fechaPropina} setFechaPropina={setFechaPropina} turno={turno} setTurno={setTurno} pagadoPor={pagadoPor} setPagadoPor={setPagadoPor} monto={monto} setMonto={setMonto} cobroRow={cobroRow} montoNum={montoNum} totalHs={totalHs} ratePH={ratePH} guardarPropina={guardarPropina} guardarBorrador={guardarBorrador} flash={flash} togglePill={togglePill}/>}
        {tab==="borradores"&&<BorradoresTab borradores={borradores} personal={personal} delBorrador={delBorrador} convertirBorrador={convertirBorrador} convertMode={convertMode} setConvertMode={setConvertMode}/>}
        {tab==="historial"&&<HistorialTab historial={historial} expandedId={expandedId} setExpandedId={setExpandedId} toggleCobrado={toggleCobrado} eliminarReg={eliminarReg}/>}
        {tab==="registros"&&<RegistrosTab personal={personal} historial={historial} selectedEmp={selectedEmp} setSelectedEmp={setSelectedEmp}/>}
        {tab==="personal"&&<PersonalTab personal={personal} nuevoNombre={nuevoNombre} setNuevoNombre={setNuevoNombre} addPersonal={addPersonal} delPersonal={delPersonal}/>}
      </div>

      <FooterBar fixed />
      <div style={{position:"fixed",bottom:0,left:"50%",transform:"translateX(-50%)",width:"100%",maxWidth:500,background:CARD,borderTop:`1px solid ${BORDER}`,display:"flex",zIndex:20,overflowX:"auto"}}>
        {TABS.map(t=>(
          <button key={t.id} onClick={()=>setTab(t.id)} style={{flex:1,minWidth:70,background:"none",border:"none",padding:"6px 0 8px",cursor:"pointer",display:"flex",flexDirection:"column",alignItems:"center",gap:2}}>
            <span style={{fontSize:18}}>{t.icon}</span>
            <span style={{fontSize:11,color:tab===t.id?BRIGHT:MUTED,fontWeight:tab===t.id?600:500,fontFamily:FONT,whiteSpace:"nowrap"}}>{t.label}</span>
            {tab===t.id&&<div style={{width:20,height:2,background:BRIGHT,borderRadius:1}}/>}
          </button>
        ))}
      </div>
    </div>
  );
}

function RegistrarTab({personal,distrib,updDistrib,fechaPago,setFechaPago,fechaPropina,setFechaPropina,turno,setTurno,pagadoPor,setPagadoPor,monto,setMonto,cobroRow,montoNum,totalHs,ratePH,guardarPropina,guardarBorrador,flash,togglePill}){
  return(
    <div>
      <div style={CARD_S}>
        <div style={SECTIT}>Datos de la propina</div>
        <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:10,marginBottom:12}}>
          <div><label style={LABEL}>Fecha de pago</label><input type="date" value={fechaPago} onChange={e=>setFechaPago(e.target.value)} style={INPUT}/></div>
          <div><label style={LABEL}>Fecha propina</label><input type="date" value={fechaPropina} onChange={e=>setFechaPropina(e.target.value)} style={INPUT}/></div>
        </div>
        <div style={{marginBottom:12}}>
          <label style={LABEL}>Turno</label>
          <div style={{display:"flex",gap:8}}>{TURNOS.map(t=><button key={t} onClick={()=>togglePill(t,turno,setTurno)} style={pill(turno===t)}>{t}</button>)}</div>
        </div>
        <div style={{marginBottom:12}}>
          <label style={LABEL}>Pagado por</label>
          <div style={{display:"flex",gap:8}}>{PAGADORES.map(p=><button key={p} onClick={()=>togglePill(p,pagadoPor,setPagadoPor)} style={pill(pagadoPor===p)}>{p}</button>)}</div>
        </div>
        <div>
          <label style={LABEL}>Monto de la propina</label>
          <div style={{position:"relative"}}>
            <span style={{position:"absolute",left:13,top:"50%",transform:"translateY(-50%)",color:BRIGHT,fontWeight:700,fontSize:16,pointerEvents:"none"}}>$</span>
            <input type="number" inputMode="decimal" value={monto} onChange={e=>setMonto(e.target.value)} placeholder="0.00" style={{...INPUT,paddingLeft:28}}/>
          </div>
        </div>
      </div>

      {montoNum>0&&totalHs>0&&(
        <div style={{background:CARD2,border:`1px solid ${BORDER}`,borderRadius:10,padding:"10px 14px",marginBottom:12,display:"flex",justifyContent:"space-between"}}>
          <span style={{fontSize:14,color:MUTED}}>Total horas: <b style={{color:BRIGHT}}>{totalHs}h</b></span>
          <span style={{fontSize:14,color:MUTED}}>Valor/hora: <b style={{color:BRIGHT}}>${ratePH.toFixed(2)}</b></span>
        </div>
      )}

      <div style={CARD_S}>
        <div style={SECTIT}>Distribución del personal</div>
        {personal.length===0?(
          <div style={{color:MUTED,fontSize:13,textAlign:"center",padding:"16px 0"}}>Agregá empleados primero</div>
        ):PUESTOS.map((puesto,i)=>{
          const row=distrib[i],cobro=cobroRow(row);
          return(
            <div key={puesto} style={{borderBottom:i<PUESTOS.length-1?`1px solid ${BORDER}`:"none",paddingBottom:12,marginBottom:12}}>
              {puesto==="Cocina 1"&&<div style={{fontSize:9,color:MUTED,letterSpacing:2.5,textTransform:"uppercase",marginBottom:8,paddingTop:4,borderTop:`1px dashed ${BORDER}`}}>— Área de Cocina —</div>}
              <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:6}}>
                <span style={{fontSize:14,color:ACCENT,fontWeight:600}}>{puesto}</span>
                <span style={{fontSize:15,fontWeight:700,color:cobro>0?GREEN:MUTED}}>{fmtN(cobro)}</span>
              </div>
              <select value={row.empId} onChange={e=>updDistrib(i,"empId",e.target.value)} style={{...INPUT,marginBottom:row.empId?8:0}}>
                <option value="">— Sin asignar —</option>
                {personal.map(p=><option key={p.id} value={p.id}>{p.nombre}</option>)}
              </select>
              {row.empId&&<div style={{display:"flex",gap:6}}>{[4,6,8].map(h=><button key={h} onClick={()=>updDistrib(i,"horas",h)} style={pill(row.horas===h)}>{h}h</button>)}</div>}
            </div>
          );
        })}
      </div>

      {montoNum>0&&totalHs>0&&distrib.some(r=>r.empId&&r.horas>0)&&(
        <div style={{...CARD_S,borderColor:"#333"}}>
          <div style={SECTIT}>Resumen</div>
          <div style={{display:"flex",justifyContent:"space-between",paddingBottom:6,borderBottom:`1px solid ${BORDER}`,marginBottom:4}}>
            <span style={{fontSize:11,color:MUTED,fontWeight:600}}>Empleado</span>
            <span style={{fontSize:11,color:MUTED,fontWeight:600}}>PAGÓ</span>
          </div>
          {distrib.filter(r=>r.empId&&r.horas>0).map((r,i)=>(
            <div key={i} style={{display:"flex",justifyContent:"space-between",padding:"6px 0",borderBottom:`1px solid ${BORDER}22`,fontSize:13}}>
              <div><span style={{color:MUTED,fontSize:11}}>{r.puesto} · </span><span style={{color:BRIGHT}}>{personal.find(p=>p.id===r.empId)?.nombre}</span><span style={{color:MUTED,fontSize:11}}> ({r.horas}h)</span></div>
              <span style={{color:GREEN,fontWeight:600}}>{fmtN(cobroRow(r))}</span>
            </div>
          ))}
          <div style={{display:"flex",justifyContent:"space-between",marginTop:10,paddingTop:8,borderTop:`1px solid ${BORDER}`}}>
            <span style={{color:MUTED,fontSize:13}}>Total propina</span>
            <span style={{color:BRIGHT,fontWeight:700,fontSize:16}}>${montoNum.toFixed(2)}</span>
          </div>
        </div>
      )}

      <div style={{display:"flex",gap:8,marginBottom:20}}>
        <button onClick={guardarBorrador} style={{flex:1,padding:"14px",background:"#2f3642",border:"none",borderRadius:14,color:"#fff",fontFamily:FONT,fontSize:15,fontWeight:700,cursor:"pointer"}}>
          📝 Guardar Borrador
        </button>
        <button onClick={guardarPropina} disabled={!montoNum} style={{flex:1,padding:"14px",background:montoNum?"#111":"#9ca3af",border:"none",borderRadius:14,color:"#fff",fontFamily:FONT,fontSize:15,fontWeight:700,cursor:montoNum?"pointer":"not-allowed",opacity:montoNum?1:0.5}}>
          {flash?"✓ Guardado!":"💾 Guardar Propina"}
        </button>
      </div>
    </div>
  );
}

function BorradoresTab({borradores,personal,delBorrador,convertirBorrador,convertMode,setConvertMode}){
  const[monto,setMonto]=useState("");

  if(borradores.length===0)return(
    <div style={{textAlign:"center",padding:"64px 20px",color:MUTED}}>
      <div style={{fontSize:44,marginBottom:14}}>📝</div>
      <div style={{fontSize:15}}>No hay borradores guardados</div>
    </div>
  );

  return(
    <div>
      <div style={{fontSize:10,color:ACCENT,letterSpacing:2.5,textTransform:"uppercase",fontWeight:600,marginBottom:14}}>
        {borradores.length} borrador{borradores.length!==1?"s":""}
      </div>
      {sortByFechaDesc(borradores).map(b=>(
        <div key={b.id} style={{background:CARD,border:`1px solid ${BORDER}`,borderRadius:14,padding:"16px",marginBottom:10}}>
          <div style={{display:"flex",justifyContent:"space-between",alignItems:"flex-start",marginBottom:12}}>
            <div>
              <div style={{fontWeight:600,fontSize:15,color:BRIGHT}}>{fmtDate(b.fechaPropina)}</div>
              <div style={{fontSize:11,color:MUTED,marginTop:2}}>{b.turno} · Pagó {b.pagadoPor}</div>
              <div style={{fontSize:10,color:MUTED,marginTop:4}}>👤 {b.distribucion.filter(r=>r.empId).length} empleado{b.distribucion.filter(r=>r.empId).length!==1?"s":""} · 🕐 {b.distribucion.reduce((s,r)=>s+(r.empId&&r.horas>0?r.horas:0),0)}h</div>
            </div>
            <button onClick={()=>delBorrador(b.id)} style={{background:RDIM,border:`1px solid ${RED}44`,borderRadius:8,color:RED,padding:"6px 12px",fontFamily:FONT,fontSize:11,cursor:"pointer"}}>🗑 Eliminar</button>
          </div>

          {convertMode===b.id?(
            <div style={{background:CARD2,border:`1px solid ${BORDER}`,borderRadius:10,padding:"12px",marginTop:12}}>
              <label style={LABEL}>Ingresá el monto total de la propina</label>
              <div style={{display:"flex",gap:8}}>
                <div style={{position:"relative",flex:1}}>
                  <span style={{position:"absolute",left:12,top:"50%",transform:"translateY(-50%)",color:BRIGHT,fontWeight:700,pointerEvents:"none"}}>$</span>
                  <input type="number" inputMode="decimal" value={monto} onChange={e=>setMonto(e.target.value)} placeholder="0.00" style={{...INPUT,paddingLeft:28,marginBottom:0}}/>
                </div>
                <button onClick={()=>{convertirBorrador(b,monto);setMonto("");setConvertMode(null);}} style={{padding:"12px 20px",background:GREEN,border:"none",borderRadius:10,color:"#000",fontFamily:FONT,fontWeight:700,cursor:"pointer"}}>Convertir</button>
                <button onClick={()=>{setMonto("");setConvertMode(null);}} style={{padding:"12px 16px",background:"none",border:`1px solid ${BORDER}`,borderRadius:10,color:MUTED,fontFamily:FONT,cursor:"pointer"}}>Cancelar</button>
              </div>
            </div>
          ):(
            <button onClick={()=>setConvertMode(b.id)} style={{width:"100%",padding:"10px",background:GREEN+"33",border:`1px solid ${GREEN}44`,borderRadius:10,color:GREEN,fontFamily:FONT,fontWeight:600,cursor:"pointer",marginTop:12}}>→ Convertir a Propina</button>
          )}
        </div>
      ))}
    </div>
  );
}

function HistorialTab({historial,expandedId,setExpandedId,toggleCobrado,eliminarReg}){
  const[confirmDel,setConfirmDel]=useState(null);
  const tc=(t)=>t==="Mañana"?"#fbbf24":t==="Noche"?"#818cf8":"#34d399";

  if(historial.length===0)return(
    <div style={{textAlign:"center",padding:"64px 20px",color:MUTED}}>
      <div style={{fontSize:44,marginBottom:14}}>📋</div>
      <div style={{fontSize:15}}>No hay propinas registradas aún</div>
    </div>
  );

  return(
    <div>
      <div style={{fontSize:10,color:ACCENT,letterSpacing:2.5,textTransform:"uppercase",fontWeight:600,marginBottom:14}}>
        {historial.length} propina{historial.length!==1?"s":""}
      </div>
      {sortByFechaDesc(historial).map(h=>{
        const cobrados=h.detalles?.filter(d=>d.cobrado).length||0,total=h.detalles?.length||0,allDone=total>0&&cobrados===total;
        return(
          <div key={h.id} style={{background:CARD,border:`1px solid ${allDone?GREEN+"55":BORDER}`,borderRadius:14,marginBottom:10,overflow:"hidden"}}>
            <div style={{padding:"14px 16px",cursor:"pointer"}} onClick={()=>setExpandedId(expandedId===h.id?null:h.id)}>
              <div style={{display:"flex",justifyContent:"space-between",alignItems:"flex-start"}}>
                <div>
                  <div style={{fontWeight:600,fontSize:15,color:BRIGHT,marginBottom:3}}>
                    {fmtDate(h.fechaPropina)}
                    <span style={{marginLeft:8,fontSize:11,color:tc(h.turno),background:tc(h.turno)+"22",padding:"2px 8px",borderRadius:20}}>{h.turno}</span>
                  </div>
                  <div style={{fontSize:12,color:MUTED}}>Pagó: <b style={{color:BRIGHT}}>{h.pagadoPor}</b> · Creado por {h.createdBy}</div>
                </div>
                <div style={{textAlign:"right"}}>
                  <div style={{fontWeight:700,fontSize:20,color:BRIGHT}}>${Number(h.monto).toFixed(2)}</div>
                  <div style={{fontSize:11,color:allDone?GREEN:MUTED}}>{allDone?"✓ Todos":`${cobrados}/${total}`}</div>
                </div>
              </div>
              <div style={{color:MUTED,fontSize:11,textAlign:"center",marginTop:8}}>{expandedId===h.id?"▲":"▼"}</div>
            </div>

            {expandedId===h.id&&(
              <div style={{borderTop:`1px solid ${BORDER}`,padding:"12px 16px"}}>
                {(h.detalles||[]).map((d,i)=>(
                  <div key={i} onClick={()=>toggleCobrado(h.id,i)} style={{display:"flex",justifyContent:"space-between",alignItems:"center",padding:"10px 12px",marginBottom:6,borderRadius:10,background:d.cobrado?GDIM:CARD2,border:`1px solid ${d.cobrado?GREEN+"55":BORDER}`,cursor:"pointer"}}>
                    <div style={{display:"flex",alignItems:"center",gap:10}}>
                      <div style={{width:26,height:26,borderRadius:"50%",flexShrink:0,background:d.cobrado?GREEN:"transparent",border:`2px solid ${d.cobrado?GREEN:BORDER}`,display:"flex",alignItems:"center",justifyContent:"center"}}>
                        {d.cobrado&&<span style={{fontSize:14,color:"#000",fontWeight:700}}>✓</span>}
                      </div>
                      <div>
                        <div style={{fontSize:14,color:d.cobrado?GREEN:RED,fontWeight:500}}>{d.empNombre}</div>
                        <div style={{fontSize:11,color:MUTED}}>{d.puesto} · {d.horas}h</div>
                      </div>
                    </div>
                    <div style={{textAlign:"right"}}>
                      <div style={{color:d.cobrado?GREEN:RED,fontWeight:700,fontSize:15}}>${Number(d.cobro).toFixed(2)}</div>
                      <div style={{fontSize:10,color:d.cobrado?GREEN:RED}}>{d.cobrado?"Pagado":"Pendiente"}</div>
                    </div>
                  </div>
                ))}
                <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginTop:12,paddingTop:10,borderTop:`1px solid ${BORDER}`}}>
                  <span style={{fontSize:12,color:MUTED}}>\$${Number(h.ratePH||0).toFixed(2)}/h</span>
                  {confirmDel===h.id?(
                    <div style={{display:"flex",gap:6}}>
                      <button onClick={()=>{eliminarReg(h.id);setConfirmDel(null);}} style={{padding:"6px 12px",background:RDIM,border:`1px solid ${RED}`,borderRadius:8,color:RED,fontFamily:FONT,fontSize:12,cursor:"pointer"}}>Sí, eliminar</button>
                      <button onClick={()=>setConfirmDel(null)} style={{padding:"6px 10px",background:"none",border:`1px solid ${BORDER}`,borderRadius:8,color:MUTED,fontFamily:FONT,fontSize:12,cursor:"pointer"}}>No</button>
                    </div>
                  ):(
                    <button onClick={()=>setConfirmDel(h.id)} style={{padding:"6px 14px",background:RDIM,border:`1px solid ${RED}44`,borderRadius:8,color:RED,fontFamily:FONT,fontSize:12,cursor:"pointer"}}>🗑 Eliminar</button>
                  )}
                </div>
              </div>
            )}
          </div>
        );
      })}
    </div>
  );
}

function RegistrosTab({personal,historial,selectedEmp,setSelectedEmp}){
  const [fechaDesde,setFechaDesde]=useState("");
  const [fechaHasta,setFechaHasta]=useState("");
  const tc=(t)=>t==="Mañana"?"#fbbf24":t==="Noche"?"#818cf8":"#34d399";
  const enviarWhatsApp=(emp,registros)=>{
    const lineas=[`🍽️ *FAROGESTION - PROPINERO*\n`,`👤 *${emp.nombre}*\n`];
    sortByFechaAsc(registros).forEach(h=>{
      const det=h.detalles?.find(d=>d.empId===emp.id);
      if(det){
        lineas.push(`📅 ${fmtDate(h.fechaPropina)} - ${h.turno}`);
        lineas.push(`📍 ${det.puesto} · ${det.horas}h`);
        lineas.push(`💰 $${Number(det.cobro).toFixed(2)} ${det.cobrado?"Pagado":"Pendiente"}`);
        lineas.push("");
      }
    });
    const total=registros.reduce((sum,h)=>{const det=h.detalles?.find(d=>d.empId===emp.id);return sum+(det?Number(det.cobro):0);},0);
    lineas.push(`💵 *Total cobrado: $${total.toFixed(2)}*`);
    lineas.push(`\n_Enviado desde FaroGestion Propinero_`);
    const msg=encodeURIComponent(lineas.join("\n"));
    if(navigator.share){navigator.share({text:lineas.join("\n")}).catch(()=>{window.open(`https://wa.me/?text=${msg}`,"_blank");});}else{window.open(`https://wa.me/?text=${msg}`,"_blank");}
  };

  if(selectedEmp){
    const emp=personal.find(p=>p.id===selectedEmp);
    const baseRegistros=historial.filter(h=>h.detalles?.some(d=>d.empId===selectedEmp));
    const filtrados=baseRegistros.filter(h=>{
      if(fechaDesde&&h.fechaPropina<fechaDesde)return false;
      if(fechaHasta&&h.fechaPropina>fechaHasta)return false;
      return true;
    });
    const registros=sortByFechaAsc(filtrados);
    const total=registros.reduce((sum,h)=>{const det=h.detalles?.find(d=>d.empId===selectedEmp);return sum+(det?Number(det.cobro):0);},0);
    return(
      <div>
        <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:14}}>
          <button onClick={()=>setSelectedEmp(null)} style={{background:"none",border:`1px solid ${BORDER}`,borderRadius:10,color:MUTED,padding:"8px 14px",fontFamily:FONT,fontSize:14,cursor:"pointer"}}>← Volver</button>
          <button onClick={()=>enviarWhatsApp(emp,registros)} style={{background:"#25d366",border:"none",borderRadius:10,color:"#000",padding:"8px 16px",fontFamily:FONT,fontSize:14,fontWeight:700,cursor:"pointer"}}>📲 WhatsApp</button>
        </div>
        <div style={{...CARD_S,marginBottom:16}}>
          <div style={{display:"flex",alignItems:"center",gap:14,marginBottom:12}}>
            <div style={{width:46,height:46,borderRadius:"50%",background:CARD2,border:`2px solid ${ACCENT}`,display:"flex",alignItems:"center",justifyContent:"center",fontSize:20,color:BRIGHT,fontWeight:700}}>{emp?.nombre[0].toUpperCase()}</div>
            <div><div style={{fontSize:20,fontWeight:700,color:BRIGHT}}>{emp?.nombre}</div><div style={{fontSize:13,color:MUTED}}>{registros.length} propinas</div></div>
            <div style={{marginLeft:"auto",textAlign:"right"}}><div style={{fontSize:11,color:MUTED}}>Total cobrado</div><div style={{fontSize:20,fontWeight:700,color:GREEN}}>${total.toFixed(2)}</div></div>
          </div>
          <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:10}}>
            <div>
              <label style={LABEL}>Desde</label>
              <input type="date" value={fechaDesde} onChange={e=>setFechaDesde(e.target.value)} style={INPUT}/>
            </div>
            <div>
              <label style={LABEL}>Hasta</label>
              <input type="date" value={fechaHasta} onChange={e=>setFechaHasta(e.target.value)} style={INPUT}/>
            </div>
          </div>
          <div style={{display:"flex",justifyContent:"flex-end",marginTop:10}}>
            <button
              onClick={()=>{setFechaDesde("");setFechaHasta("");}}
              disabled={!fechaDesde&&!fechaHasta}
              style={{padding:"8px 12px",background:"none",border:`1px solid ${BORDER}`,borderRadius:8,color:!fechaDesde&&!fechaHasta?"#9aa1ad":MUTED,fontFamily:FONT,fontSize:13,cursor:!fechaDesde&&!fechaHasta?"not-allowed":"pointer"}}
            >
              Limpiar fechas
            </button>
          </div>
        </div>
        {registros.length===0?(<div style={{textAlign:"center",padding:"40px 20px",color:MUTED}}>📭 No hay propinas en ese rango</div>):registros.map(h=>{const det=h.detalles?.find(d=>d.empId===selectedEmp);return(<div key={h.id} style={{background:CARD,border:`1px solid ${BORDER}`,borderRadius:12,padding:"14px 16px",marginBottom:8}}><div style={{display:"flex",justifyContent:"space-between",alignItems:"flex-start"}}><div><div style={{fontWeight:600,fontSize:14,color:BRIGHT}}>{fmtDate(h.fechaPropina)}<span style={{marginLeft:8,fontSize:11,color:tc(h.turno),background:tc(h.turno)+"22",padding:"2px 7px",borderRadius:20}}>{h.turno}</span></div><div style={{fontSize:11,color:MUTED}}>{det?.puesto} · {det?.horas}h · Pagó {h.pagadoPor}</div></div><div style={{textAlign:"right"}}><div style={{fontWeight:700,fontSize:18,color:det?.cobrado?GREEN:RED}}>${Number(det?.cobro||0).toFixed(2)}</div><div style={{fontSize:10,color:det?.cobrado?GREEN:RED}}>{det?.cobrado?"Pagado":"Pendiente"}</div></div></div></div>);})}
      </div>
    );
  }

  return(
    <div>
      <div style={{fontSize:10,color:ACCENT,letterSpacing:2.5,textTransform:"uppercase",fontWeight:600,marginBottom:14}}>Seleccioná un empleado</div>
      {personal.length===0?(<div style={{textAlign:"center",padding:"48px 20px",color:MUTED}}>👤 No hay empleados</div>):(<div style={{background:CARD,border:`1px solid ${BORDER}`,borderRadius:14,overflow:"hidden"}}>{personal.map((p,i)=>{const cant=historial.filter(h=>h.detalles?.some(d=>d.empId===p.id)).length;const total=historial.reduce((sum,h)=>{const det=h.detalles?.find(d=>d.empId===p.id);return sum+(det?Number(det.cobro):0);},0);return(<div key={p.id} onClick={()=>setSelectedEmp(p.id)} style={{display:"flex",alignItems:"center",justifyContent:"space-between",padding:"14px 16px",borderBottom:i<personal.length-1?`1px solid ${BORDER}`:"none",cursor:"pointer"}}><div style={{display:"flex",alignItems:"center",gap:12}}><div style={{width:38,height:38,borderRadius:"50%",background:CARD2,border:`1px solid ${ACCENT}44`,display:"flex",alignItems:"center",justifyContent:"center",fontSize:16,color:BRIGHT,fontWeight:700}}>{p.nombre[0].toUpperCase()}</div><div><div style={{fontSize:15,fontWeight:500,color:BRIGHT}}>{p.nombre}</div><div style={{fontSize:11,color:MUTED}}>{cant} propinas</div></div></div><div style={{textAlign:"right"}}><div style={{fontSize:15,fontWeight:700,color:GREEN}}>{total>0?`$${total.toFixed(2)}`:"—"}</div><div style={{fontSize:10,color:MUTED}}>total</div></div></div>);})}</div>)}
    </div>
  );
}

function PersonalTab({personal,nuevoNombre,setNuevoNombre,addPersonal,delPersonal}){
  const[confirmId,setConfirmId]=useState(null);
  return(
    <div>
      <div style={{fontSize:10,color:ACCENT,letterSpacing:2.5,textTransform:"uppercase",fontWeight:600,marginBottom:14}}>
        Base de datos · {personal.length} empleado{personal.length!==1?"s":""}
      </div>
      <div style={{display:"flex",gap:8,marginBottom:16}}>
        <input value={nuevoNombre} onChange={e=>setNuevoNombre(e.target.value)} onKeyDown={e=>e.key==="Enter"&&addPersonal()} placeholder="Nombre del empleado..." style={{...INPUT,flex:1}}/>
        <button onClick={addPersonal} style={{padding:"12px 20px",background:"#ffffff",border:"none",borderRadius:10,color:"#000",fontFamily:FONT,fontSize:20,fontWeight:700,cursor:"pointer",flexShrink:0}}>+</button>
      </div>
      {personal.length===0?(<div style={{textAlign:"center",padding:"48px 20px",color:MUTED}}>👥 No hay empleados</div>):(<div style={{background:CARD,border:`1px solid ${BORDER}`,borderRadius:14,overflow:"hidden"}}>{personal.map((p,i)=>(<div key={p.id} style={{display:"flex",alignItems:"center",justifyContent:"space-between",padding:"13px 16px",borderBottom:i<personal.length-1?`1px solid ${BORDER}`:"none"}}><div style={{display:"flex",alignItems:"center",gap:12}}><div style={{width:36,height:36,borderRadius:"50%",background:CARD2,border:`1px solid ${ACCENT}44`,display:"flex",alignItems:"center",justifyContent:"center",fontSize:14,color:BRIGHT,fontWeight:700}}>{p.nombre[0].toUpperCase()}</div><span style={{fontSize:15,fontWeight:500,color:BRIGHT}}>{p.nombre}</span></div>{confirmId===p.id?(<div style={{display:"flex",gap:6}}><button onClick={()=>{delPersonal(p.id);setConfirmId(null);}} style={{padding:"6px 12px",background:RDIM,border:`1px solid ${RED}`,borderRadius:8,color:RED,fontFamily:FONT,fontSize:12,cursor:"pointer"}}>Sí, borrar</button><button onClick={()=>setConfirmId(null)} style={{padding:"6px 10px",background:"none",border:`1px solid ${BORDER}`,borderRadius:8,color:MUTED,fontFamily:FONT,fontSize:12,cursor:"pointer"}}>No</button></div>):(<button onClick={()=>setConfirmId(p.id)} style={{padding:"6px 14px",background:"none",border:`1px solid ${BORDER}`,borderRadius:8,color:MUTED,fontFamily:FONT,fontSize:12,cursor:"pointer"}}>Eliminar</button>)}</div>))}</div>)}
    </div>
  );
}
